concept.codeExample:
/* Quick snippet to test effect of an index (Postgres) */
-- Before: slow sequential scan
EXPLAIN ANALYZE SELECT id, name FROM users WHERE email = 'alice@example.com';

-- Add index
CREATE UNIQUE INDEX users_email_idx ON users(email);
ANALYZE users;

-- After: index scan should appear
EXPLAIN ANALYZE SELECT id, name FROM users WHERE email = 'alice@example.com';
